class MemberCashCard(CashCard):
    def __init__(self, id, amount, points=0):
        super().__init__(id, amount)
        self.__points = points

    @property
    def points(self):
        return self.__points

    def earnPoints(self, amount):
        self.__points += int(amount)

    def topUp(self, amount):
        super().topUp(amount)
        self.earnPoints(amount)

from abc import ABC, abstractmethod

class Shape(ABC):
    @abstractmethod
    def area(self):
        pass

    @abstractmethod
    def perimeter(self):
        pass

    def describe(self):
        return f'Shape with area: {self.area()}'
